#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    // Read entire stdin into a buffer
    fseek(stdin, 0, SEEK_END);
    long len = ftell(stdin);
    fseek(stdin, 0, SEEK_SET);
    char *buf = (char *)malloc(len + 1);
    if (!buf) return 0;
    fread(buf, 1, len, stdin);
    buf[len] = '\0';

    // Replace literal "\\n" with a space so they become normal delimiters
    for (long i = 0; i + 1 < len; ) {
        if (buf[i] == '\\' && buf[i + 1] == 'n') {
            memmove(buf + i, buf + i + 2, len - (i + 2) + 1);
            len -= 2;
        } else {
            i++;
        }
    }

    // Tokenise the cleaned buffer
    char *token = strtok(buf, " \t\r\n");
    if (!token) {
        free(buf);
        return 0;
    }
    int T = atoi(token);
    for (int tc = 0; tc < T; ++tc) {
        token = strtok(NULL, " \t\r\n");
        int N = atoi(token);
        long long first = 0, third = 0, x;
        for (int i = 0; i < N; ++i) {
            token = strtok(NULL, " \t\r\n");
            x = atoll(token);
            if (i == 0) first = x;
            if (i == 2) third = x;
        }
        printf("%lld", first * third);
        if (tc != T - 1) printf("\\n");
    }
    free(buf);
    return 0;
}

