    // Read whole input
    string all((istreambuf_iterator<char>(cin)), istreambuf_iterator<char>());
    // Replace literal "\\n" with a space
    for (size_t i = 0; i + 1 < all.size(); ) {
        if (all[i] == '\\' && all[i + 1] == 'n') {
            all.replace(i, 2, " ");
        } else ++i;
    }
    stringstream ss(all);
    int T; ss >> T;
    while (T--) {
        int N; ss >> N;
        long long first = 0, third = 0, x;
        for (int i = 0; i < N; ++i) {
            ss >> x;
            if (i == 0) first = x;
            if (i == 2) third = x;
        }
        cout << first * third;
        if (T) cout << "\\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire stdin as a single string
        byte[] allBytes = System.in.readAllBytes();
        String all = new String(allBytes, StandardCharsets.UTF_8);
        // Replace literal "\\n" with a space so tokenisation works
        all = all.replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(all);
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int N = Integer.parseInt(st.nextToken());
            long first = 0, third = 0;
            for (int i = 0; i < N; ++i) {
                long val = Long.parseLong(st.nextToken());
                if (i == 0) first = val;
                if (i == 2) third = val;
            }
            sb.append(first * third);
            if (tc != T - 1) sb.append("\\n");
        }
        System.out.print(sb.toString());
    }
}

